"use strict";(self.webpackChunkblog=self.webpackChunkblog||[]).push([[302],{9853:(s,a,n)=>{n.r(a),n.d(a,{data:()=>e});const e={key:"v-1871f861",path:"/notes/Others/shell/shell_echo.html",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"shell echo 命令",slug:"shell-echo-命令",children:[{level:3,title:"显示普通的字符串",slug:"显示普通的字符串",children:[]},{level:3,title:"显示转义的字符串",slug:"显示转义的字符串",children:[]},{level:3,title:"显示变量",slug:"显示变量",children:[]},{level:3,title:"显示转义字符",slug:"显示转义字符",children:[]},{level:3,title:"将结果定向显示到文件中",slug:"将结果定向显示到文件中",children:[]},{level:3,title:"将结果原样输出",slug:"将结果原样输出",children:[]},{level:3,title:"显示命令执行结果",slug:"显示命令执行结果",children:[]}]}],filePathRelative:"notes/Others/shell/shell_echo.md",git:{updatedTime:null,contributors:[]}}},2640:(s,a,n)=>{n.r(a),n.d(a,{default:()=>t});const e=(0,n(6252).uE)('<h2 id="shell-echo-命令" tabindex="-1"><a class="header-anchor" href="#shell-echo-命令" aria-hidden="true">#</a> shell echo 命令</h2><p>echo的基本用法：</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token builtin class-name">echo</span> string\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="显示普通的字符串" tabindex="-1"><a class="header-anchor" href="#显示普通的字符串" aria-hidden="true">#</a> 显示普通的字符串</h3><p>引号可以完全省略，效果与加上双引号一样</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token builtin class-name">echo</span> <span class="token string">&quot;Hello World!&quot;</span>\n<span class="token builtin class-name">echo</span> Hello World<span class="token operator">!</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><details class="custom-container details"><summary>点击查看输出内容</summary><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>Hello World<span class="token operator">!</span>\nHello World<span class="token operator">!</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><h3 id="显示转义的字符串" tabindex="-1"><a class="header-anchor" href="#显示转义的字符串" aria-hidden="true">#</a> 显示转义的字符串</h3><p>引号可以完全省略，效果与加上双引号一样</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token builtin class-name">echo</span> <span class="token punctuation">\\</span>&quot;It is a test<span class="token punctuation">\\</span>&quot;\n<span class="token builtin class-name">echo</span> <span class="token string">&quot;<span class="token entity" title="\\&quot;">\\&quot;</span>It is a test<span class="token entity" title="\\&quot;">\\&quot;</span>&quot;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><details class="custom-container details"><summary>点击查看输出内容</summary><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>It is a <span class="token builtin class-name">test</span>\nIt is a <span class="token builtin class-name">test</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><h3 id="显示变量" tabindex="-1"><a class="header-anchor" href="#显示变量" aria-hidden="true">#</a> 显示变量</h3><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>name <span class="token operator">=</span> <span class="token string">&quot;OK&quot;</span>\n<span class="token builtin class-name">echo</span> <span class="token string">&quot;<span class="token variable">$name</span> It is a test&quot;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><details class="custom-container details"><summary>点击查看输出内容</summary><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>OK It is a <span class="token builtin class-name">test</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div></details><h3 id="显示转义字符" tabindex="-1"><a class="header-anchor" href="#显示转义字符" aria-hidden="true">#</a> 显示转义字符</h3><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token builtin class-name">echo</span> -e <span class="token string">&quot;OK! <span class="token entity" title="\\n">\\n</span>&quot;</span>\n<span class="token builtin class-name">echo</span> <span class="token string">&quot;It is a test!&quot;</span>\n\n<span class="token builtin class-name">echo</span> -e <span class="token string">&quot;OK! <span class="token entity" title="\\c">\\c</span>&quot;</span>\n<span class="token builtin class-name">echo</span> <span class="token string">&quot;It is a test!&quot;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><details class="custom-container details"><summary>点击查看输出内容</summary><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># -e 开启转义 \\n 表示换行 \\c 表示不换行</span>\nOK<span class="token operator">!</span> \n\nIt is a test<span class="token operator">!</span>\n\nOK<span class="token operator">!</span> \nIt is a test<span class="token operator">!</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div></details><h3 id="将结果定向显示到文件中" tabindex="-1"><a class="header-anchor" href="#将结果定向显示到文件中" aria-hidden="true">#</a> 将结果定向显示到文件中</h3><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token builtin class-name">echo</span> <span class="token string">&quot;It is a test&quot;</span> <span class="token operator">&gt;</span> myfile\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><details class="custom-container details"><summary>点击查看输出内容</summary><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># myfile</span>\nIt is a <span class="token builtin class-name">test</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><h3 id="将结果原样输出" tabindex="-1"><a class="header-anchor" href="#将结果原样输出" aria-hidden="true">#</a> 将结果原样输出</h3><p>原样输出字符串，不进行转义或取变量(用单引号)</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token builtin class-name">echo</span> <span class="token string">&#39;$name\\&quot;&#39;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><details class="custom-container details"><summary>点击查看输出内容</summary><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token variable">$name</span><span class="token punctuation">\\</span>&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div></details><h3 id="显示命令执行结果" tabindex="-1"><a class="header-anchor" href="#显示命令执行结果" aria-hidden="true">#</a> 显示命令执行结果</h3><p>使用反引号</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token builtin class-name">echo</span> <span class="token variable"><span class="token variable">`</span><span class="token function">date</span><span class="token variable">`</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><details class="custom-container details"><summary>点击查看输出内容</summary><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token number">2021</span>年 <span class="token number">9</span>月24日 星期五 <span class="token number">19</span>时43分30秒 CST\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div></details>',28),l={},t=(0,n(3744).Z)(l,[["render",function(s,a){return e}]])},3744:(s,a)=>{a.Z=(s,a)=>{for(const[n,e]of a)s[n]=e;return s}}}]);